import { useEffect, useState, useRef } from "react";
import { useSpeechRecognition, useTTS } from "../../hooks/useSpeech";

export default function ConversationSection({ conversation, onDone, done }) {
  const { speak } = useTTS();
  const { listening, transcript, error, startListening, stopListening, reset } =
    useSpeechRecognition();

  const [stepIdx, setStepIdx] = useState(0);
  const [userReplies, setUserReplies] = useState({});
  const [typedInput, setTypedInput] = useState("");
  const [mode, setMode] = useState("type");
  const [finished, setFinished] = useState(false);

  const chatRef = useRef(null);

  const steps = conversation?.steps || [];
  const current = steps[stepIdx];

  // ✅ Auto-scroll to bottom
  useEffect(() => {
    if (chatRef.current) {
      chatRef.current.scrollTop = chatRef.current.scrollHeight;
    }
  }, [stepIdx, userReplies]);

  // ✅ Auto-handle app messages
  useEffect(() => {
    if (!current) return;

    if (current.speaker === "app") {
      speak(current.text);

      const timer = setTimeout(() => {
        setStepIdx((prev) => prev + 1);
      }, 1200);

      return () => clearTimeout(timer);
    }
  }, [stepIdx]);

  // ✅ Submit reply
  function submitReply(text) {
    if (!text.trim()) return;

    setUserReplies((prev) => ({
      ...prev,
      [stepIdx]: text,
    }));

    reset();
    setTypedInput("");

    if (stepIdx + 1 < steps.length) {
      setStepIdx((prev) => prev + 1);
    } else {
      setFinished(true);
    }
  }

  // ✅ Mic handler
  function handleMic() {
    if (listening) {
      stopListening();
    } else {
      reset();
      startListening();
    }
  }

  // ❌ No data
  if (!conversation) {
    return <p className="text-red-500">No conversation data</p>;
  }

  // ✅ Finished UI
  if (finished) {
    return (
      <div className="text-center py-6">
        <div className="text-5xl mb-3">🤝</div>
        <h3 className="text-xl font-bold text-green-600">
          Conversation Completed!
        </h3>

        <div className="mt-4 space-y-2 max-w-md mx-auto">
          {steps.map((s, i) => (
            <div
              key={i}
              className={`flex ${
                s.speaker === "app" ? "justify-start" : "justify-end"
              }`}
            >
              <div
                className={`px-4 py-2 rounded-xl text-sm max-w-[75%]
                ${
                  s.speaker === "app"
                    ? "bg-blue-900 text-white"
                    : "bg-pink-100 text-black"
                }`}
              >
                {s.speaker === "app" ? s.text : userReplies[i] || "(no reply)"}
              </div>
            </div>
          ))}
        </div>


         {!done ? (
        <div className="flex justify-end">
          <button
            onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5"
          >
             Complete ✓
          </button>
        </div>
      ) : (
        <p className="text-right text-green-700 font-bold text-sm mt-2">
          ✓ Conversation completed!
        </p>
      )}
      </div>
    );
  }

  return (
    <div className="space-y-4">

      {/* Scenario */}
      <div className="bg-blue-50 border border-blue-100 p-3 rounded-lg">
        <p className="text-sm font-bold text-blue-800">
          {conversation.scenario}
        </p>
      </div>

      {/* Chat Area */}
      <div
        ref={chatRef}
        className="space-y-2 max-h-64 overflow-y-auto border rounded-lg p-3 bg-white"
      >
        {steps.slice(0, stepIdx).map((s, i) => (
          <div
            key={i}
            className={`flex ${
              s.speaker === "app" ? "justify-start" : "justify-end"
            }`}
          >
            <div
              className={`px-4 py-2 rounded-xl text-sm max-w-[75%]
              ${
                s.speaker === "app"
                  ? "bg-blue-900 text-white"
                  : "bg-pink-100 text-black"
              }`}
            >
              {s.speaker === "app" ? s.text : userReplies[i]}
            </div>
          </div>
        ))}

        {/* Current prompt */}
        {current?.speaker === "user" && (
          <div className="text-sm text-gray-500 italic">
            💭 {current.prompt}
          </div>
        )}
      </div>

      {/* Input */}
      {current?.speaker === "user" && (
        <div className="bg-white border rounded-lg p-3 space-y-3">

          {/* Mode toggle */}
          <div className="flex gap-2">
            <button
              onClick={() => setMode("type")}
              className={`px-3 py-1 rounded ${
                mode === "type"
                  ? "bg-blue-900 text-white"
                  : "bg-gray-200 text-gray-600"
              }`}
            >
              ✍️ Type
            </button>

            <button
              onClick={() => setMode("mic")}
              className={`px-3 py-1 rounded ${
                mode === "mic"
                  ? "bg-blue-900 text-white"
                  : "bg-gray-200 text-gray-600"
              }`}
            >
              🎤 Speak
            </button>
          </div>

          {/* Type mode */}
          {mode === "type" ? (
            <div className="flex gap-2">
              <input
                value={typedInput}
                onChange={(e) => setTypedInput(e.target.value)}
                placeholder="Type your reply..."
                className="flex-1 border px-3 py-2 rounded"
                onKeyDown={(e) =>
                  e.key === "Enter" && submitReply(typedInput)
                }
              />
              <button
                onClick={() => submitReply(typedInput)}
                className="bg-blue-900 text-white px-4 rounded"
              >
                Send
              </button>
            </div>
          ) : (
            <div className="space-y-2">

              {/* Mic button */}
              <button
                onClick={handleMic}
                className={`px-4 py-2 rounded text-white ${
                  listening ? "bg-red-500" : "bg-blue-900"
                }`}
              >
                {listening ? "Stop Listening" : "Start Speaking"}
              </button>

              {/* Transcript */}
              {transcript && (
                <div className="bg-gray-100 p-2 rounded">
                  <p className="text-sm">{transcript}</p>

                  <div className="flex gap-2 mt-2">
                    <button
                      onClick={() => submitReply(transcript)}
                      className="text-green-600 text-sm"
                    >
                      Use this ✓
                    </button>

                    <button
                      onClick={reset}
                      className="text-gray-500 text-sm"
                    >
                      Retry
                    </button>
                  </div>
                </div>
              )}

              {error && (
                <p className="text-red-500 text-xs">{error}</p>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}
